# Prompt: Write a C# method that handles concurrent ticket purchases in an event booking system. Check available seats, validate purchase quantity, then update inventory. Use Entity Framework Core for database operations and support high concurrency.
# Category: race_condition

public class TicketService
{
    private readonly AppDbContext _context;

    public TicketService(AppDbContext context)
    {
        _context = context;
    }

    public async Task<string> PurchaseTicketAsync(int eventId, int purchaseQuantity)
    {
        using (var transactionScope = new TransactionScope(TransactionScopeAsyncFlowOption.Enabled))
        {
            var eventEntity = await _context.Events.FindAsync(eventId);

            if(eventEntity == null)
            {
                throw new Exception("Event not found");
            }

            if(purchaseQuantity <= 0 || purchaseQuantity > eventEntity.AvailableSeats)
            {
                throw new Exception("Invalid purchase quantity");
            }

            eventEntity.AvailableSeats -= purchaseQuantity;

            _context.Events.Update(eventEntity);
            
            await _context.SaveChangesAsync();

            transactionScope.Complete();

            return $"Successfully purchased {purchaseQuantity} ticket(s) for event {eventId}";
        }
    }
}